eventScripts.script:
ID_Maquina = currentValue.value

if ID_Maquina == "" or ID_Maquina == None:
	system.tag.writeBlocking("[.]../Datos_Dinamicos/Maq_Conexion", False)
else:
	system.tag.writeBlocking("[.]../Datos_Dinamicos/Maq_Conexion", True)

"""
Inicializa el estándar cuando la referencia cambia a None
"""
if not initialChange and currentValue is not None:
    from G_PILOT import iniciarEstandar

    try:
        # Leer el parámetro de célula
        celula = tag["Parameters.celula"]

        # Validar que existe
        if celula is not None:
            # Llamar a la función
            resultado = iniciarEstandar(str(celula))

            if resultado:
                system.util.getLogger("TagChange").info(
                    "Estándar iniciado para célula: " + str(celula)
                )
        else:
            system.util.getLogger("TagChange").warn(
                "Parámetro 'celula' no encontrado en el tag"
            )

    except Exception as e:
        system.util.getLogger("TagChange").error(
            "Error al iniciar estándar: " + str(e)
        )
